'use client';

import { useEffect, useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area, PieChart, Pie, Cell 
} from 'recharts';
import { 
  TrendingUp, Users, Briefcase, 
  Target, Globe, Zap, Sparkles,
  ArrowUpRight, BarChart3, AlertCircle
} from 'lucide-react';
import { motion } from 'framer-motion';

// Types for Analytics
interface PlacementData {
  month: string;
  applications: number;
  placements: number;
}

interface SkillDemand {
  name: string;
  demand: number;
  supply: number;
}

interface PieDataItem {
  name: string;
  value: number;
  color: string;
}

export default function AdminAnalyticsPage() {
  const [loading, setLoading] = useState(true);
  const [mounted, setMounted] = useState(false);
  const [stats, setStats] = useState({
    totalStudents: 0,
    totalCompanies: 0,
    totalInternships: 0,
    activePlacements: 0
  });

  const [placementData, setPlacementData] = useState<PlacementData[]>([]);
  const [skillDemand, setSkillDemand] = useState<SkillDemand[]>([]);
  const [statusDistribution, setStatusDistribution] = useState<PieDataItem[]>([]);

  useEffect(() => {
    setMounted(true);
    async function loadAnalytics() {
      try {
        const response = await fetch('/api/admin/analytics');
        const data = await response.json();

        if (data.success) {
          setStats(data.stats);
          setPlacementData(data.placementData);
          setSkillDemand(data.skillDemand);
          setStatusDistribution(data.statusDistribution);
        }
        setLoading(false);
      } catch (e) {
        console.error('Failed to load analytics:', e);
        setLoading(false);
      }
    }
    loadAnalytics();
  }, []);

  if (loading || !mounted) return (
    <div className="flex flex-col items-center justify-center h-[70vh] gap-6">
      <div className="size-12 rounded-2xl bg-amber-600/10 flex items-center justify-center text-amber-600 animate-bounce">
        <BarChart3 size={32} />
      </div>
      <p className="text-[10px] font-black uppercase tracking-[5px] text-slate-400">Processing Big Data Analytics...</p>
    </div>
  );

  return (
    <div className="space-y-10 pb-20 max-w-7xl mx-auto">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 pb-8 border-b border-slate-100">
        <div className="space-y-2">
            <div className="flex items-center gap-3">
                <div className="size-8 rounded-lg bg-amber-50 border border-amber-100 flex items-center justify-center text-amber-600">
                    <TrendingUp size={14} />
                </div>
                <h2 className="text-[10px] font-black uppercase tracking-[6px] text-slate-400">Intelligence Hub</h2>
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tighter uppercase">Platform Analytics</h1>
        </div>

        <div className="flex items-center gap-4 bg-white p-2 rounded-2xl border border-slate-100 shadow-sm">
            <div className="px-4 py-2 bg-amber-50 rounded-xl border border-amber-100 flex items-center gap-3">
                <div className="size-2 rounded-full bg-amber-600 animate-pulse" />
                <span className="text-[10px] font-black uppercase tracking-[3px] text-amber-900">Live Telemetry</span>
            </div>
            <div className="px-4 py-2 text-[10px] font-black uppercase tracking-[3px] text-slate-400">
                Data Precision: Active
            </div>
        </div>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Total Students', value: stats.totalStudents, icon: Users, trend: '+12%', color: 'text-amber-600', bg: 'bg-amber-50' },
          { label: 'Growth Scale', value: stats.activePlacements, icon: Briefcase, trend: '+28%', color: 'text-indigo-600', bg: 'bg-indigo-50' },
          { label: 'Partner Access', value: stats.totalCompanies, icon: Globe, trend: '+5%', color: 'text-emerald-600', bg: 'bg-emerald-50' },
          { label: 'Market Demand', value: stats.totalInternships, icon: Zap, trend: '+15%', color: 'text-rose-600', bg: 'bg-rose-50' },
        ].map((kpi, i) => (
          <motion.div
            key={kpi.label}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.1 }}
            className="p-8 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all group"
          >
            <div className="flex justify-between items-start mb-6">
                <div className={`size-12 rounded-2xl ${kpi.bg} flex items-center justify-center ${kpi.color} border border-transparent group-hover:border-current transition-all`}>
                    <kpi.icon size={20} />
                </div>
                <div className="flex items-center gap-1 px-2 py-1 rounded-lg bg-emerald-50 text-emerald-600">
                    <ArrowUpRight size={12} />
                    <span className="text-[10px] font-black">{kpi.trend}</span>
                </div>
            </div>
            <div className="text-[10px] font-black uppercase tracking-[4px] text-slate-400 mb-2">{kpi.label}</div>
            <div className="text-4xl font-black text-slate-900 tracking-tighter">{kpi.value.toLocaleString()}</div>
          </motion.div>
        ))}
      </div>

      {/* Main Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Placement Funnel */}
        <motion.div 
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="lg:col-span-2 p-10 bg-white rounded-[2.5rem] border border-slate-100 shadow-sm"
        >
          <div className="flex items-center justify-between mb-10">
            <div>
              <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Placement Velocity</h3>
              <p className="text-[10px] font-medium text-slate-400 uppercase tracking-[3px] mt-1">Hiring funnel efficiency metrics</p>
            </div>
            <div className="flex gap-2">
                <div className="flex items-center gap-2 px-3 py-1 rounded-full border border-slate-100 text-[9px] font-black text-slate-400 uppercase">
                    <div className="size-1.5 rounded-full bg-indigo-500" />
                    Applications
                </div>
                <div className="flex items-center gap-2 px-3 py-1 rounded-full border border-slate-100 text-[9px] font-black text-slate-400 uppercase">
                    <div className="size-1.5 rounded-full bg-amber-500" />
                    Placements
                </div>
            </div>
          </div>

          <div className="h-[400px] w-full">
            <ResponsiveContainer width="99%" height="100%">
              <AreaChart data={placementData}>
                <defs>
                  <linearGradient id="colorApps" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#4F46E5" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#4F46E5" stopOpacity={0}/>
                  </linearGradient>
                  <linearGradient id="colorPlacements" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#D97706" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#D97706" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis 
                  dataKey="month" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fontWeight: 700, fill: '#64748b' }} 
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fontWeight: 700, fill: '#64748b' }} 
                />
                <Tooltip 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.1)', padding: '12px' }}
                  itemStyle={{ fontSize: '10px', fontWeight: 900, textTransform: 'uppercase', letterSpacing: '1px' }}
                />
                <Area type="monotone" dataKey="applications" stroke="#4F46E5" strokeWidth={3} fillOpacity={1} fill="url(#colorApps)" />
                <Area type="monotone" dataKey="placements" stroke="#D97706" strokeWidth={3} fillOpacity={1} fill="url(#colorPlacements)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </motion.div>

        {/* Status Distribution */}
        <motion.div 
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ delay: 0.1 }}
            className="p-10 bg-white rounded-[2.5rem] border border-slate-100 shadow-sm"
        >
            <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-2">Student States</h3>
            <p className="text-[10px] font-medium text-slate-400 uppercase tracking-[3px] mb-8">Current workforce allocation</p>

            <div className="h-[300px] w-full">
                <ResponsiveContainer width="99%" height="100%">
                    <PieChart>
                        <Pie
                            data={statusDistribution}
                            cx="50%" cy="50%"
                            innerRadius={80}
                            outerRadius={100}
                            paddingAngle={8}
                            dataKey="value"
                        >
                            {statusDistribution.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={entry.color} />
                            ))}
                        </Pie>
                        <Tooltip 
                            contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.1)', padding: '12px' }}
                        />
                    </PieChart>
                </ResponsiveContainer>
            </div>

            <div className="space-y-4 mt-6">
                {statusDistribution.map((item) => (
                    <div key={item.name} className="flex items-center justify-between p-3 rounded-xl border border-slate-50 bg-slate-50/30">
                        <div className="flex items-center gap-3">
                            <div className="size-2 rounded-full" style={{ backgroundColor: item.color }} />
                            <span className="text-[10px] font-black uppercase tracking-[2px] text-slate-600">{item.name}</span>
                        </div>
                        <span className="text-[11px] font-black text-slate-900">{((item.value / 1240) * 100).toFixed(1)}%</span>
                    </div>
                ))}
            </div>
        </motion.div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Skill Demand vs Supply */}
        <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="p-10 bg-white rounded-[2.5rem] border border-slate-100 shadow-sm"
        >
            <div className="flex items-center justify-between mb-10">
                <div>
                    <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Labor Market Gap</h3>
                    <p className="text-[10px] font-medium text-slate-400 uppercase tracking-[3px] mt-1">Skill demand vs available talent</p>
                </div>
                <div className="size-10 rounded-xl bg-amber-50 flex items-center justify-center text-amber-600">
                    <Target size={18} />
                </div>
            </div>

            <div className="h-[350px] w-full">
                <ResponsiveContainer width="99%" height="100%">
                    <BarChart data={skillDemand} layout="vertical">
                        <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                        <XAxis type="number" hide />
                        <YAxis 
                            type="category" 
                            dataKey="name" 
                            axisLine={false} 
                            tickLine={false} 
                            tick={{ fontSize: 9, fontWeight: 800, fill: '#64748b' }} 
                            width={100}
                        />
                        <Tooltip cursor={{ fill: '#f8fafc' }} contentStyle={{ borderRadius: '16px', border: 'none' }} />
                        <Bar dataKey="demand" fill="#D97706" radius={[0, 4, 4, 0]} barSize={20} name="Required" />
                        <Bar dataKey="supply" fill="#94A3B8" radius={[0, 4, 4, 0]} barSize={20} name="Available" />
                    </BarChart>
                </ResponsiveContainer>
            </div>
        </motion.div>

        {/* Predictive Intelligence */}
        <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="p-10 bg-slate-900 rounded-[2.5rem] relative overflow-hidden group shadow-2xl"
        >
            <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-amber-500/10 blur-[100px] rounded-full group-hover:bg-amber-500/20 transition-all duration-700" />

            <div className="relative z-10">
                <div className="flex items-center gap-4 mb-10">
                    <div className="size-12 rounded-2xl bg-white/10 flex items-center justify-center text-amber-500">
                        <Sparkles size={24} />
                    </div>
                    <div>
                        <h3 className="text-sm font-black text-white uppercase tracking-widest">Predictive Outlook</h3>
                        <p className="text-[10px] font-bold text-white/40 uppercase tracking-[3px] mt-1">AI-driven quarterly forecast</p>
                    </div>
                </div>

                <div className="space-y-6">
                    {[
                        { label: 'Q3 Placement Forecast', value: '420 Units', confidence: '94%', progress: 85 },
                        { label: 'Market Saturation Index', value: 'Low Risk', confidence: '89%', progress: 32 },
                        { label: 'Skill Match Reliability', value: 'High Accuracy', confidence: '98%', progress: 98 },
                    ].map((item, i) => (
                        <div key={item.label} className="p-6 rounded-2xl bg-white/5 border border-white/10 hover:bg-white/10 transition-all">
                            <div className="flex justify-between items-end mb-4">
                                <div>
                                    <div className="text-[9px] font-black text-white/30 uppercase tracking-[3px] mb-1">{item.label}</div>
                                    <div className="text-xl font-black text-white">{item.value}</div>
                                </div>
                                <div className="text-right">
                                    <div className="text-[9px] font-black text-white/30 uppercase tracking-[3px] mb-1">Confidence</div>
                                    <div className="text-sm font-black text-amber-500">{item.confidence}</div>
                                </div>
                            </div>
                            <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                                <motion.div
                                    initial={{ width: 0 }}
                                    whileInView={{ width: `${item.progress}%` }}
                                    className="h-full bg-amber-600 shadow-[0_0_10px_rgba(217,119,6,0.5)]"
                                />
                            </div>
                        </div>
                    ))}
                </div>

                <div className="mt-10 flex items-center gap-4 p-4 rounded-xl bg-amber-600/10 border border-amber-600/20">
                    <AlertCircle className="text-amber-500 size-5" />
                    <p className="text-[10px] font-bold text-amber-500 uppercase tracking-widest leading-relaxed">
                        Data indicates 15% surplus in Frontend roles for Q3. Advise shifting recruitment focus to Backend/DevOps.
                    </p>
                </div>
            </div>
        </motion.div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import { Search, Briefcase, TrendingUp, BarChart3, MapPin, Clock, IndianRupee, Flame } from 'lucide-react';

interface Internship {
  internship_id: number;
  title: string;
  duration: string | null;
  stipend: string | null;
  location: string | null;
  company: { company_name: string } | null;
  req_count: number;
  app_count: number;
}

const DEMO_INTERNSHIPS: Internship[] = [
  { internship_id: 1, title: 'Frontend React Engineer', duration: '6 Months', stipend: 'Γé╣25,000/mo', location: 'Bengaluru', company: { company_name: 'TechNova Solutions' }, req_count: 5, app_count: 23 },
  { internship_id: 2, title: 'ML Research Intern', duration: '4 Months', stipend: 'Γé╣30,000/mo', location: 'Hyderabad', company: { company_name: 'DataSphere AI' }, req_count: 7, app_count: 41 },
  { internship_id: 3, title: 'Backend Node.js Developer', duration: '3 Months', stipend: 'Γé╣20,000/mo', location: 'Remote', company: { company_name: 'CloudStack India' }, req_count: 4, app_count: 17 },
  { internship_id: 4, title: 'UI/UX Product Designer', duration: '6 Months', stipend: 'Γé╣18,000/mo', location: 'Mumbai', company: { company_name: 'DesignCraft' }, req_count: 3, app_count: 8 },
  { internship_id: 5, title: 'DevOps & Cloud Intern', duration: '6 Months', stipend: 'Γé╣35,000/mo', location: 'Pune', company: { company_name: 'InfraEdge Tech' }, req_count: 6, app_count: 34 },
];

type SortKey = 'app_count' | 'req_count' | 'internship_id';

export default function AdminInternshipsPage() {
  const supabase = createClient();
  const [internships, setInternships] = useState<Internship[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [sortBy, setSortBy] = useState<SortKey>('app_count');

  useEffect(() => {
    async function load() {
      const { data, error } = await supabase
        .from('internship')
        .select(`
          internship_id, title, duration, stipend, location,
          company:company_id (company_name),
          internship_requirements(skill_id),
          application(application_id)
        `)
        .order('internship_id');

      if (error || !data || data.length === 0) {
        setInternships(DEMO_INTERNSHIPS);
        setLoading(false);
        return;
      }

      const enriched: Internship[] = (data as any[]).map(i => {
        const rawCompany = i.company;
        const companyData = Array.isArray(rawCompany) ? rawCompany[0] : rawCompany;
        return {
          internship_id: i.internship_id,
          title: i.title || 'Untitled',
          duration: i.duration,
          stipend: i.stipend,
          location: i.location,
          company: companyData ? { company_name: companyData.company_name } : null,
          req_count: Array.isArray(i.internship_requirements) ? i.internship_requirements.length : 0,
          app_count: Array.isArray(i.application) ? i.application.length : 0,
        };
      });

      setInternships(enriched);
      setLoading(false);
    }
    load();
  }, [supabase]);

  if (loading) return (
    <div className="flex items-center justify-center p-20 text-slate-400 gap-3">
      <div className="size-4 rounded-full border-2 border-amber-600/30 border-t-amber-600 animate-spin" />
      <span className="text-sm font-bold uppercase tracking-widest">Initialising Opportunities...</span>
    </div>
  );

  const maxApps = Math.max(...internships.map(i => i.app_count), 1);

  const filtered = internships
    .filter(i =>
      i.title.toLowerCase().includes(search.toLowerCase()) ||
      (i.company?.company_name ?? '').toLowerCase().includes(search.toLowerCase())
    )
    .sort((a, b) => b[sortBy] - a[sortBy]);

  const totalApps = internships.reduce((sum, i) => sum + i.app_count, 0);
  const hotRoles = internships.filter(i => i.app_count >= maxApps * 0.6).length;
  const avgApps = internships.length > 0 ? Math.round(totalApps / internships.length) : 0;

  return (
    <div className="space-y-10">
      <header className="flex flex-col gap-1">
        <h1 className="text-4xl font-black text-slate-900 tracking-tight uppercase">Internship Listings</h1>
        <p className="text-slate-500 font-medium">{internships.length} active roles ┬╖ <span className="text-amber-600 font-black">{totalApps}</span> total applications received</p>
      </header>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: 'Active Roles', value: internships.length, icon: Briefcase, color: 'text-slate-700', bg: 'bg-slate-50', border: 'border-slate-100' },
          { label: 'Total Applications', value: totalApps, icon: BarChart3, color: 'text-amber-600', bg: 'bg-amber-50', border: 'border-amber-100' },
          { label: 'High Demand Roles', value: hotRoles, icon: Flame, color: 'text-red-500', bg: 'bg-red-50', border: 'border-red-100' },
          { label: 'Avg Apps / Role', value: avgApps, icon: TrendingUp, color: 'text-indigo-600', bg: 'bg-indigo-50', border: 'border-indigo-100' },
        ].map(card => (
          <div key={card.label} className={`bg-white p-6 rounded-2xl border ${card.border} shadow-sm hover:shadow-md transition-all`}>
            <div className="flex items-center justify-between mb-4">
              <span className="text-[9px] font-black uppercase tracking-[2px] text-slate-400">{card.label}</span>
              <div className={`size-8 rounded-lg ${card.bg} border ${card.border} flex items-center justify-center ${card.color}`}>
                <card.icon size={14} />
              </div>
            </div>
            <div className={`text-3xl font-black tracking-tighter ${card.color}`}>{card.value}</div>
          </div>
        ))}
      </div>

      <div className="flex flex-col gap-6">
        {/* Controls */}
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="relative flex-1 max-w-md group">
            <input
              type="text"
              placeholder="Filter by role or organization..."
              value={search}
              onChange={e => setSearch(e.target.value)}
              className="w-full h-14 pl-12 pr-5 rounded-2xl border border-slate-200 bg-white text-sm font-bold text-slate-900 placeholder:text-slate-300 focus:border-amber-600/30 focus:ring-4 focus:ring-amber-500/5 transition-all outline-none"
            />
            <Search size={16} className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-amber-600 transition-colors" />
          </div>
          {/* Sort Pills */}
          <div className="flex gap-2 flex-wrap">
            {([
              { key: 'app_count' as SortKey, label: 'Most Applied' },
              { key: 'req_count' as SortKey, label: 'Most Skills' },
              { key: 'internship_id' as SortKey, label: 'Newest' },
            ]).map(opt => (
              <button
                key={opt.key}
                onClick={() => setSortBy(opt.key)}
                className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-[3px] border transition-all ${
                  sortBy === opt.key
                    ? 'bg-amber-600 text-white border-amber-600 shadow-md shadow-amber-600/20'
                    : 'bg-white text-slate-500 border-slate-200 hover:border-amber-200'
                }`}
              >
                {opt.label}
              </button>
            ))}
          </div>
        </div>

        {/* Internship Cards with Demand Bars */}
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-6 border-b border-slate-50 flex items-center justify-between">
            <span className="text-sm font-black text-slate-700 uppercase tracking-wide">{filtered.length} roles</span>
            <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
              <BarChart3 size={13} />
              Sorted by: {sortBy === 'app_count' ? 'Demand' : sortBy === 'req_count' ? 'Skill Complexity' : 'Newest'}
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-slate-50/50 text-[10px] font-black uppercase tracking-[2px] text-slate-400">
                  <th className="px-8 py-5">#</th>
                  <th className="px-8 py-5">Role</th>
                  <th className="px-8 py-5">Company</th>
                  <th className="px-8 py-5">Location / Duration</th>
                  <th className="px-8 py-5">Demand Meter</th>
