import { NextResponse } from 'next/server';
import connectDB from '@/lib/db';
import Student from '@/models/Student';
import Internship from '@/models/Internship';
import Application from '@/models/Application';
import Company from '@/models/Company';
import { Student as IStudent, Internship as IInternship, Application as IApplication } from '@/types';

export async function GET() {
  try {
    await connectDB();

    const [students, internships, applications, companies] = await Promise.all([
      Student.find({}).lean() as Promise<IStudent[]>,
      Internship.find({}).lean() as Promise<IInternship[]>,
      Application.find({}).lean() as Promise<IApplication[]>,
      Company.find({}).lean() as Promise<any[]>
    ]);

    // 1. Placement Velocity (Monthly)
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];
    const placementVelocity = months.map((month, idx) => {
      // Mocked historical data trend based on current DB density
      const baseApps = applications.length;
      const basePlacements = applications.filter(a => a.status === 'Accepted').length;

      const multiplier = (idx + 1) / months.length;
      return {
        month,
        applications: Math.round(baseApps * multiplier) + 5,
        placements: Math.round(basePlacements * multiplier) + 2
      };
    });

    // 2. Skill Demand vs Supply
    const skillSupplyMap: Record<string, number> = {};
    const skillDemandMap: Record<string, number> = {};

    students.forEach(s => {
      s.skills.forEach(sk => {
        skillSupplyMap[sk.skill_name] = (skillSupplyMap[sk.skill_name] || 0) + 1;
      });
    });

    internships.forEach(i => {
      i.requirements.role_skills.forEach(sk => {
        skillDemandMap[sk] = (skillDemandMap[sk] || 0) + 1;
      });
    });

    const topSkills = ['React', 'Node.js', 'Python', 'SQL', 'AWS', 'Machine Learning'];
    const skillGaps = topSkills.map(name => ({
      name,
      demand: (skillDemandMap[name] || 0) * 10 + 20, // Scaled for demo data density
      supply: (skillSupplyMap[name] || 0) * 10 + 15
    }));

    // 3. Status Distribution
    const statusCounts = {
      Placed: applications.filter(a => a.status === 'Accepted').length,
      Interviewing: applications.filter(a => a.status === 'Interviewing').length,
      Searching: students.length - applications.filter(a => a.status === 'Accepted').length
    };

    const statusDistribution = [
      { name: 'Placed', value: statusCounts.Placed || 480, color: '#D97706' },
      { name: 'Interviewing', value: statusCounts.Interviewing || 320, color: '#4F46E5' },
      { name: 'Searching', value: statusCounts.Searching || 440, color: '#94A3B8' },
    ];

    return NextResponse.json({
      success: true,
      stats: {
        totalStudents: students.length,
        totalCompanies: companies.length,
        totalInternships: internships.length,
        activePlacements: applications.filter(a => a.status === 'Accepted').length
      },
      placementData: placementVelocity,
      skillDemand: skillGaps,
      statusDistribution
    });
  } catch (error: unknown) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    return NextResponse.json({ success: false, error: message }, { status: 500 });
  }
}

