          setApplications(data.applications);
          setTalentDiscovery(data.talentDiscovery);
        }
        setLoading(false);
      } catch (e) {
        console.error('Failed to load company dashboard:', e);
        setLoading(false);
      }
    }
    load();
  }, [supabase]);

  if (loading) return (
    <div className="flex items-center justify-center p-20 text-slate-400 gap-3">
