                                        </div>
                                        <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                                            <motion.div 
                                                initial={{ width: 0 }}
                                                animate={{ width: `${config.progress}%` }}
                                                className={`h-full rounded-full ${
                                                    ms.proficiency_level === 'Expert' ? 'bg-amber-600' :
                                                    ms.proficiency_level === 'Advanced' ? 'bg-amber-500' :
                                                    ms.proficiency_level === 'Intermediate' ? 'bg-amber-400' : 'bg-slate-300'
                                                }`}
                                            />
                                        </div>
                                    </div>

                                    <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                                        <div className="flex items-center gap-3">
                                            <div className="size-8 rounded-lg bg-slate-50 flex items-center justify-center text-slate-400 group-hover:bg-amber-50 group-hover:text-amber-600 transition-colors">
                                                <Database size={14} />
                                            </div>
                                            <div className="text-[9px] font-black text-slate-400 uppercase tracking-[2px]">
                                                {ms.skill?.category || 'General Focus'}
                                            </div>
                                        </div>
                                        <div className="inline-flex items-center gap-1.5 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full border border-emerald-100/50">
                                            <ShieldCheck size={10} />
                                            <span className="text-[8px] font-black uppercase tracking-[1px]">Verified</span>
                                        </div>
                                    </div>

                                    {/* Visual Accent */}
                                    <div className={`absolute top-0 left-0 bottom-0 w-1 ${
                                        ms.proficiency_level === 'Expert' ? 'bg-amber-600' : 'bg-slate-100'
                                    }`} />
                                </motion.div>
                            );
                        })}
                    </AnimatePresence>
                </div>
            )}
         </div>
      </div>
    </div>
  );
}

