'use client';

import { useTheme } from "next-themes";
import { Sun, Moon } from "lucide-react";
import { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

export function ThemeToggle() {
  const { theme, setTheme } = useTheme();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return (
      <div className="size-10 rounded-xl bg-muted/20 border border-border/50" />
    );
  }

  return (
    <motion.button
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
      className="relative size-10 rounded-xl bg-background/50 border border-border/50 flex items-center justify-center text-foreground hover:bg-accent hover:text-accent-foreground transition-all group overflow-hidden shadow-sm"
      aria-label="Toggle theme"
    >
      <AnimatePresence mode="wait" initial={false}>
        {theme === "dark" ? (
          <motion.div
            key="moon"
            initial={{ y: 20, opacity: 0, rotate: 45 }}
            animate={{ y: 0, opacity: 1, rotate: 0 }}
            exit={{ y: -20, opacity: 0, rotate: -45 }}
            transition={{ duration: 0.3, ease: "circOut" }}
          >
            <Moon size={18} className="text-primary group-hover:scale-110 transition-transform" />
          </motion.div>
        ) : (
          <motion.div
            key="sun"
            initial={{ y: 20, opacity: 0, rotate: -45 }}
            animate={{ y: 0, opacity: 1, rotate: 0 }}
            exit={{ y: -20, opacity: 0, rotate: 45 }}
            transition={{ duration: 0.3, ease: "circOut" }}
          >
            <Sun size={18} className="text-amber-500 group-hover:scale-110 transition-transform" />
          </motion.div>
        )}
      </AnimatePresence>
      <div className="absolute inset-x-0 bottom-0 h-[2px] bg-primary/20 opacity-0 group-hover:opacity-100 transition-opacity" />
    </motion.button>
  );
}

'use client';

import { useTheme } from 'next-themes';
import { Sun, Moon, Monitor } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useEffect, useState } from 'react';

export default function ThemeToggle() {
  const { theme, setTheme } = useTheme();
  const [mounted, setMounted] = useState(false);

  useEffect(() => setMounted(true), []);

  if (!mounted) return <div className="size-10 rounded-xl bg-muted/20 animate-pulse" />;

  const toggleTheme = () => {
    setTheme(theme === 'dark' ? 'light' : 'dark');
  };

  return (
    <motion.button
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      onClick={toggleTheme}
      className="relative size-10 rounded-xl bg-card border border-border shadow-lg flex items-center justify-center text-foreground hover:border-primary/50 transition-colors group"
      aria-label="Toggle Theme"
    >
      <AnimatePresence mode="wait">
        {theme === 'dark' ? (
          <motion.div
            key="moon"
            initial={{ y: 20, opacity: 0, rotate: -45 }}
            animate={{ y: 0, opacity: 1, rotate: 0 }}
            exit={{ y: -20, opacity: 0, rotate: 45 }}
            transition={{ duration: 0.2 }}
          >
            <Moon size={20} className="text-emerald-400 group-hover:text-emerald-300" />
          </motion.div>
        ) : (
          <motion.div
            key="sun"
            initial={{ y: 20, opacity: 0, rotate: 45 }}
            animate={{ y: 0, opacity: 1, rotate: 0 }}
            exit={{ y: -20, opacity: 0, rotate: -45 }}
            transition={{ duration: 0.2 }}
          >
            <Sun size={20} className="text-emerald-600 group-hover:text-emerald-700" />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Visual Indicator */}
      <div className="absolute -top-1 -right-1 size-2 rounded-full bg-primary shadow-[0_0_8px_rgba(16,185,129,0.5)]" />
    </motion.button>
  );
}

import mongoose from 'mongoose';

const MONGODB_URI = process.env.MONGODB_URI;

if (!MONGODB_URI) {
  throw new Error('Please define the MONGODB_URI environment variable inside .env.local');
}

/**
 * Global is used here to maintain a cached connection across hot reloads
 * in development. This prevents connections from growing exponentially
 * during API Route usage.
 */
let cached = (global as any).mongoose;

if (!cached) {
  cached = (global as any).mongoose = { conn: null, promise: null };
}

async function connectDB() {
  if (cached.conn) {
    return cached.conn;
  }

  if (!cached.promise) {
    const opts = {
      bufferCommands: false,
    };

    cached.promise = mongoose.connect(MONGODB_URI!, opts).then((mongoose) => {
      return mongoose;
    });
  }

  try {
    cached.conn = await cached.promise;
  } catch (e) {
    cached.promise = null;
    throw e;
  }

  return cached.conn;
}

export default connectDB;

import connectDB from './db';
import Student from '../models/Student';
import Internship from '../models/Internship';
import Application from '../models/Application';
import Company from '../models/Company';
import { DEMO_STUDENT, DEMO_INTERNSHIPS, DEMO_APPLICATIONS } from './demo-data';

export async function seedDatabase() {
  await connectDB();

  // 0. Clear Existing Data (Optional but good for first demo)
  await Student.deleteMany({});
  await Internship.deleteMany({});
  await Application.deleteMany({});
  await Company.deleteMany({});

  // 1. Seed Company
  const existingCompany = await Company.findOne({ id: 'comp_1' });
  if (!existingCompany) {
    await Company.create({
      id: 'comp_1',
      company_name: 'InnovateTech Solutions',
      industry: 'Technology'
    });
    console.log('Seeded Company');
  }

  // 2. Seed Student
  const existingStudent = await Student.findOne({ id: 'student_1' });
  if (!existingStudent) {
    await Student.create({
      ...DEMO_STUDENT,
      id: 'student_1',
      market_reach: 45 // Initial AI value
    });
    console.log('Seeded Student');
  }

  // 2. Seed Internships
  for (const intern of DEMO_INTERNSHIPS) {
    const exists = await Internship.findOne({ internship_id: intern.internship_id });
    if (!exists) {
      await Internship.create({
        ...intern,
        company_name: (intern as any).company?.company_name || 'InnovateTech',
        difficulty_score: Math.floor(Math.random() * 5) + 1
      });
    }
  }
  console.log('Seeded Internships');

  // 3. Seed Applications
  for (const app of DEMO_APPLICATIONS) {
    const exists = await Application.findOne({ application_id: app.application_id });
    if (!exists) {
      // Flatten the nested data from demo-data.ts
      await Application.create({
        ...app,
        student_id: DEMO_STUDENT.id,
        internship_id: (app as any).internship?.internship_id || 1,
        company_id: 'comp_1', // Default link to our seeded company
        ai_match_score: Math.floor(Math.random() * 40) + 60,
        ai_interview_questions: [
            "Explain your experience with the tech stack mentioned.",
            "How would you optimize the performance of this system?",
            "Describe a time you lead a technical project."
        ]
      });
    }
  }
  console.log('Seeded Applications');
}
